class SlidingWindowLimiter:
    def __init__(self, limit: int, window_seconds: int, max_keys: int = 20000):
        self.limit = limit
        self.window_seconds = window_seconds
        self.max_keys = max_keys
        self.events: dict[str, deque[float]] = defaultdict(deque)
        self.lock = Lock()

    def check(self, key: str) -> int | None:
        now = time.monotonic()
        with self.lock:
            q = self.events[key]
            cutoff = now - self.window_seconds
            while q and q[0] <= cutoff:
                q.popleft()

            if len(q) >= self.limit:
                return max(1, math.ceil(self.window_seconds - (now - q[0])))

            q.append(now)

            if len(self.events) > self.max_keys:
                for old_key in list(self.events.keys())[:1000]:
                    oq = self.events[old_key]
                    while oq and oq[0] <= cutoff:
                        oq.popleft()
                    if not oq:
                        del self.events[old_key]

            return None


