def validate_csrf_and_origin(request: Request, errors: list[dict[str, str]]) -> None:
    origin = request.headers.get("origin")
    if origin and ALLOWED_ORIGINS and origin not in ALLOWED_ORIGINS:
        add_error(errors, "security", "bad_origin", "Request origin is not allowed.")

    if request.cookies:
        csrf_cookie = request.cookies.get("csrf_token")
        csrf_header = request.headers.get("x-csrf-token")
        if not csrf_cookie or not csrf_header:
            add_error(errors, "security", "csrf_required", "CSRF token is required for cookie-authenticated requests.")
