def validate_domain_labels(domain_ascii: str, errors: list[dict[str, str]]) -> None:
    if domain_ascii in SPECIAL_EMAIL_DOMAINS or domain_ascii.endswith(SPECIAL_EMAIL_SUFFIXES):
        add_error(errors, "email", "private_domain", "Email domain is not allowed.")

    try:
        ipaddress.ip_address(domain_ascii.strip("[]"))
        add_error(errors, "email", "ip_literal_domain", "Email domain must not be an IP address.")
    except ValueError:
        pass

    labels = domain_ascii.split(".")
    if len(labels) < 2:
        add_error(errors, "email", "missing_public_suffix", "Email domain must include a public suffix.")

    label_re = re.compile(r"^[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?$")
    for label in labels:
        if not label or len(label) > 63 or not label_re.fullmatch(label):
            add_error(errors, "email", "bad_domain_label", "Email domain contains an invalid label.")
            break

    if blocked_domain(domain_ascii):
        add_error(errors, "email", "disposable_domain", "Disposable email domains are not allowed.")


def validate_email_field(value: Any, errors: list[dict[str, str]]) -> EmailParts | None:
    if value is MISSING:
        add_error(errors, "email", "required", "Email is required.")
        return None
    if not isinstance(value, str):
        add_error(errors, "email", "invalid_type", "Email must be a string.")
        return None

    raw = nfkc(value.strip())
    if not raw:
        add_error(errors, "email", "empty", "Email is required.")
        return None
    if len(raw) > 254:
        add_error(errors, "email", "too_long", "Email must be 254 characters or fewer.")
    if contains_control_or_format(raw) or any(ch.isspace() for ch in raw):
        add_error(errors, "email", "invalid_characters", "Email contains invalid or invisible characters.")
    if raw.count("@") != 1:
        add_error(errors, "email", "invalid_format", "Email must contain exactly one @ sign.")

    try:
        info = validate_email(
            raw,
            allow_smtputf8=True,
            allow_quoted_local=False,
            allow_domain_literal=False,
            check_deliverability=CHECK_EMAIL_DELIVERABILITY,
        )
    except EmailNotValidError:
        add_error(errors, "email", "invalid_format", "Email address is not valid.")
        return None

    try:
        domain_ascii = idna.encode(info.domain, uts46=True, std3_rules=True).decode("ascii").lower()
    except idna.IDNAError:
        add_error(errors, "email", "invalid_idn", "Email domain cannot be converted to a valid IDN.")
        return None

    validate_domain_labels(domain_ascii, errors)

    local = nfkc(info.local_part)
    local_canonical = local.casefold()
    canonical = f"{local_canonical}@{domain_ascii}"

    if len(local.encode("utf-8")) > 64:
        add_error(errors, "email", "local_too_long", "Email local part is too long.")
    if len(canonical.encode("utf-8")) > 254:
        add_error(errors, "email", "too_long", "Email is too long after normalization.")

    return EmailParts(original=raw, canonical=canonical, local=local_canonical, domain_ascii=domain_ascii)


def validate_username_field(value: Any, errors: list[dict[str, str]]) -> UsernameParts | None:
    if value is MISSING:
        add_error(errors, "username", "required", "Username is required.")
        return None
    if not isinstance(value, str):
        add_error(errors, "username", "invalid_type", "Username must be a string.")
        return None

    username = nfkc(value.strip())
    if not username:
        add_error(errors, "username", "empty", "Username is required.")
        return None
    if username != value.strip():
        add_error(errors, "username", "unicode_normalization", "Username must use plain ASCII characters.")
    if contains_control_or_format(username):
        add_error(errors, "username", "invalid_characters", "Username contains invalid or invisible characters.")
    if not USERNAME_RE.fullmatch(username):
        add_error(errors, "username", "invalid_format", "Username must be 3-32 chars, start with a letter, and contain only letters, numbers, and underscores.")

    canonical = username.casefold()
    if canonical in RESERVED_USERNAMES:
        add_error(errors, "username", "reserved", "Username is reserved.")
    if canonical.isdigit():
        add_error(errors, "username", "all_numeric", "Username must not be all numbers.")
    if "__" in canonical:
        add_error(errors, "username", "repeated_separator", "Username must not contain repeated separators.")
    if canonical.startswith(("xn--", "www", "http")):
        add_error(errors, "username", "impersonation_risk", "Username prefix is not allowed.")
    if contains_blocked_name_term(canonical):
        add_error(errors, "username", "blocked_language", "Username contains blocked language.")

    return UsernameParts(display=username, canonical=canonical)


def validate_display_name_field(value: Any, errors: list[dict[str, str]]) -> DisplayNameParts | None:
    if value is MISSING:
        add_error(errors, "display_name", "required", "Display name is required.")
        return None
    if not isinstance(value, str):
        add_error(errors, "display_name", "invalid_type", "Display name must be a string.")
        return None

    display_name = re.sub(r"\s+", " ", nfkc(value).strip())
    if not display_name:
        add_error(errors, "display_name", "empty", "Display name is required.")
        return None
    if len(display_name) > 80:
        add_error(errors, "display_name", "too_long", "Display name must be 80 characters or fewer.")
    if contains_control_or_format(display_name):
        add_error(errors, "display_name", "invalid_characters", "Display name contains invalid or invisible characters.")
    if HTML_TAG_RE.search(display_name) or URL_RE.search(display_name):
        add_error(errors, "display_name", "unsafe_content", "Display name must not contain HTML, URLs, or script-like content.")
    if not any(ch.isalnum() for ch in display_name):
        add_error(errors, "display_name", "no_letters_or_numbers", "Display name must contain letters or numbers.")
    if compact_name(display_name) in RESERVED_USERNAMES:
        add_error(errors, "display_name", "reserved", "Display name is reserved.")
    if contains_blocked_name_term(display_name):
        add_error(errors, "display_name", "blocked_language", "Display name contains blocked language.")

    return DisplayNameParts(value=display_name, storage_value=html.escape(display_name, quote=True))


def estimated_entropy(password: str) -> float:
    pool = 0
    if any("a" <= c <= "z" for c in password):
        pool += 26
    if any("A" <= c <= "Z" for c in password):
        pool += 26
    if any(c.isdigit() for c in password):
        pool += 10
    if any(c in r"""!"#$%&'()*+,-./:;<=>?@[\]^_`{|}~""" for c in password):
        pool += 33
    if any(ord(c) > 127 for c in password):
        pool += 50
    if any(c.isspace() for c in password):
        pool += 1
    return len(password) * math.log2(max(pool, 1))


def has_sequence(password: str) -> bool:
    lowered = password.casefold()
    sequences = ["abcdefghijklmnopqrstuvwxyz", "0123456789", "qwertyuiop", "asdfghjkl", "zxcvbnm"]
    for seq in sequences:
        for source in (seq, seq[::-1]):
            for i in range(len(source) - 3):
                if source[i:i + 4] in lowered:
                    return True
    return False


def validate_password_field(
    value: Any,
    errors: list[dict[str, str]],
    email: EmailParts | None,
    username: UsernameParts | None,
    display_name: DisplayNameParts | None,
) -> str | None:
    if value is MISSING:
        add_error(errors, "password", "required", "Password is required.")
        return None
    if not isinstance(value, str):
        add_error(errors, "password", "invalid_type", "Password must be a string.")
        return None

    password = nfkc(value)
    if password != value:
        add_error(errors, "password", "unicode_normalization", "Password contains unsupported compatibility characters.")
    if len(password) < 12:
        add_error(errors, "password", "too_short", "Password must be at least 12 characters.")
    if len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        add_error(errors, "password", "too_long", "Password is too long.")
    if contains_control_or_format(password):
        add_error(errors, "password", "invalid_characters", "Password contains invalid or invisible characters.")
    if password != password.strip():
        add_error(errors, "password", "outer_whitespace", "Password must not start or end with whitespace.")

    lowered = password.casefold()
    compact = re.sub(r"\s+", "", lowered)
    if compact in COMMON_PASSWORDS:
        add_error(errors, "password", "common_password", "Password is too common.")
    if re.search(r"(.)\1{3,}", lowered):
        add_error(errors, "password", "repeated_characters", "Password contains too many repeated characters.")
    if has_sequence(password):
        add_error(errors, "password", "sequential_characters", "Password contains an obvious sequence.")

    classes = sum([
        any(c.islower() for c in password),
        any(c.isupper() for c in password),
        any(c.isdigit() for c in password),
        any(not c.isalnum() and not c.isspace() for c in password),
    ])
    if len(password) < 16 and classes < 3:
        add_error(errors, "password", "insufficient_complexity", "Passwords under 16 characters must use at least 3 character classes.")
    if estimated_entropy(password) < 50:
        add_error(errors, "password", "low_entropy", "Password does not have enough estimated entropy.")

    forbidden_tokens = set()
    if username:
        forbidden_tokens.add(username.canonical)
    if email:
        forbidden_tokens.add(email.local.split("+", 1)[0])
        forbidden_tokens.add(email.domain_ascii.split(".", 1)[0])
    if display_name:
        dn = compact_name(display_name.value)
        if len(dn) >= 3:
            forbidden_tokens.add(dn)

    password_compact = compact_name(password)
    for token in {t for t in forbidden_tokens if len(t) >= 3}:
        if token in password_compact:
            add_error(errors, "password", "contains_personal_info", "Password must not contain username, email, or display name.")
            break
        if SequenceMatcher(None, password_compact, token).ratio() >= 0.72:
            add_error(errors, "password", "too_similar", "Password is too similar to account identifiers.")
            break

    return password


def pwned_password_count(password: str) -> int:
    if not CHECK_PWNED_PASSWORDS:
        return 0

    # SHA-1 is used only for Have I Been Pwned k-anonymity lookup, never for storage.
    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]
    req = UrlRequest(
        f"https://api.pwnedpasswords.com/range/{prefix}",
        headers={"Add-Padding": "true", "User-Agent": "registration-service"},
    )

    try:
        with urlopen(req, timeout=2.5) as response:
            body = response.read(2_000_000).decode("utf-8", "replace")
    except (OSError, URLError):
        return 1 if PWNED_FAIL_CLOSED else 0

    for line in body.splitlines():
        candidate, _, count = line.partition(":")
        if hmac.compare_digest(candidate.encode(), suffix.encode()):
            return int(count or "1")
    return 0


