@app.post("/api/register")
async def register(request: Request):
    start = time.monotonic()

    ip = client_ip(request)
    retry_after = ip_limiter.check(hmac_key(f"ip:{ip}"))
    if retry_after is not None:
        return error_response(
            429,
            [{"field": "request", "code": "rate_limited", "message": "Too many registration attempts."}],
            {"Retry-After": str(retry_after)},
        )

    content_type = request.headers.get("content-type", "").split(";", 1)[0].strip().lower()
    if content_type != "application/json" and not content_type.endswith("+json"):
        return error_response(415, [{"field": "body", "code": "unsupported_media_type", "message": "Content-Type must be application/json."}])

    body = await request.body()
    if len(body) > MAX_BODY_BYTES:
        return error_response(413, [{"field": "body", "code": "too_large", "message": "Request body is too large."}])

    try:
        payload = json.loads(body)
    except json.JSONDecodeError:
        return error_response(400, [{"field": "body", "code": "invalid_json", "message": "Request body must be valid JSON."}])

    errors: list[dict[str, str]] = []
    validate_csrf_and_origin(request, errors)

    if not isinstance(payload, dict):
        add_error(errors, "body", "invalid_type", "Request body must be a JSON object.")
        return error_response(422, errors)

    allowed = {"email", "username", "password", "display_name"}
    for extra in sorted(set(payload) - allowed):
        add_error(errors, extra, "unexpected_field", "Unexpected field.")

    email = validate_email_field(payload.get("email", MISSING), errors)
    username = validate_username_field(payload.get("username", MISSING), errors)
    display_name = validate_display_name_field(payload.get("display_name", MISSING), errors)
    password = validate_password_field(payload.get("password", MISSING), errors, email, username, display_name)

    if email and username:
        identifier_key = hmac_key(f"id:{email.canonical}:{username.canonical}")
        retry_after = identifier_limiter.check(identifier_key)
        if retry_after is not None:
            return error_response(
                429,
                [{"field": "request", "code": "rate_limited", "message": "Too many registration attempts."}],
                {"Retry-After": str(retry_after)},
            )

    if password and not any(e["field"] == "password" and e["code"] in {"invalid_type", "too_long"} for e in errors):
        breached = await asyncio.to_thread(pwned_password_count, password)
        if breached > 0:
            add_error(errors, "password", "breached_password", "Password appears in known breach data.")

    if errors:
        await pad_response(start)
        status = 403 if any(e["field"] == "security" for e in errors) else 422
        return error_response(status, errors)

    assert email and username and display_name and password

    password_hash = await asyncio.to_thread(password_hasher.hash, password)
    values = {
        "email_canonical": email.canonical,
        "email_original": html.escape(email.original, quote=True),
        "email_domain_ascii": email.domain_ascii,
        "username_canonical": username.canonical,
        "username_display": username.display,
        "display_name": display_name.storage_value,
        "password_hash": password_hash,
        "registration_ip_hash": hmac_key(f"ip-store:{ip}"),
        "created_at": time.strftime("%Y-%m-%d %H:%M:%S%z"),
    }

    await asyncio.to_thread(insert_user, values)

    # Same response for new users and duplicate email/username attempts to prevent enumeration.
    await pad_response(start)
    return JSONResponse(
        status_code=202,
        content={
